public double chiSquare(double[] expected, long[] observed) throws IllegalArgumentException {
    if (expected == null || observed == null) {
        throw new IllegalArgumentException("Input arrays cannot be null");
    }
    if ((expected.length < 2) || (expected.length != observed.length)) {
        throw new IllegalArgumentException("observed, expected array lengths incorrect");
    }
    if (!isPositive(expected) || !isNonNegative(observed)) {
        throw new IllegalArgumentException("observed counts must be non-negative and expected counts must be positive");
    }

    // Calculate the totals
    long sumObserved = 0;
    for (int i = 0; i < observed.length; i++) {
        sumObserved += observed[i];
    }
    double sumExpected = 0.0;
    for (double v : expected) {
        sumExpected += v;
    }

    // Rescale expected counts
    double ratio = (double) sumObserved / sumExpected;
    for (int i = 0; i < expected.length; i++) {
        expected[i] *= ratio;
    }

    // Calculate chi-square
    double sumSq = 0.0d;
    for (int i = 0; i < observed.length; i++) {
        double obs = (double) observed[i];
        double exp = expected[i];

        // Handle cases with very small expected values avoiding division by zero
        if (exp < 1e-10 && obs < 1e-10) {
            continue; // Both are effectively zero, skip division
        }

        double dev = obs - exp;
        sumSq += dev * dev / exp;
    }
    return sumSq;
}

